1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
14	    const result = nextGeneration([[0, 0], [0, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive when it has exactly 3 neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
19	    expect(result).toContainEqual([1, 1]);
20	  });
21	  it("should kill a live cell with 4 or more neighbors (overpopulation)", () => {
22	    const cells: Cell[] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
23	    const result = nextGeneration(cells);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("should preserve a block still life pattern unchanged", () => {
31	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(block);
33	    expect(result).toEqual(expect.arrayContaining(block));
34	    expect(result).toHaveLength(block.length);
35	  });
36	  it.todo("should oscillate a blinker pattern to its next phase");
37	});
