1	export type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean =>
4	  !(cell[0] === other[0] && cell[1] === other[1]) &&
5	  Math.abs(cell[0] - other[0]) <= 1 &&
6	  Math.abs(cell[1] - other[1]) <= 1;
7	
8	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
9	  cells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const deadNeighbors = (cells: Cell[]): Cell[] => {
12	  const alive = new Set(cells.map(([x, y]) => `${x},${y}`));
13	  const candidates = new Set<string>();
14	  for (const [x, y] of cells) {
15	    for (let dx = -1; dx <= 1; dx++) {
16	      for (let dy = -1; dy <= 1; dy++) {
17	        if (dx === 0 && dy === 0) continue;
18	        const key = `${x + dx},${y + dy}`;
19	        if (!alive.has(key)) candidates.add(key);
20	      }
21	    }
22	  }
23	  return [...candidates].map((k) => k.split(",").map(Number) as unknown as Cell);
24	};
25	
26	export function nextGeneration(cells: Cell[]): Cell[] {
27	  const hasThreeNeighbors = (cell: Cell) => countNeighbors(cell, cells) === 3;
28	  const survivors = cells.filter(hasThreeNeighbors);
29	  const born = deadNeighbors(cells).filter(hasThreeNeighbors);
30	  return [...survivors, ...born];
31	}
